import{c as d,$ as i,Q as t,j as s,m as a,h as n,ax as o,n as l,o as c,S as u}from"./chunks/framework.CPTW7DhK.js";const P=JSON.parse('{"title":"Requisitos de Hardware — Desbravador Enterprise / 4.0 — Cloud","description":"Requisitos de infraestrutura para implantação totalmente em nuvem do Desbravador Enterprise / 4.0","frontmatter":{"title":"Requisitos de Hardware — Desbravador Enterprise / 4.0 — Cloud","description":"Requisitos de infraestrutura para implantação totalmente em nuvem do Desbravador Enterprise / 4.0","audience":"Cliente / Equipe de TI","updated":"2026-05-31T00:00:00.000Z"},"headers":[],"relativePath":"desbravador-enterprise/cloud/requisitos-hardware.md","filePath":"desbravador-enterprise/cloud/requisitos-hardware.md","lastUpdated":null}'),p={name:"desbravador-enterprise/cloud/requisitos-hardware.md"};function h(m,e,b,g,v,f){const r=i("Mermaid");return t(),s("div",null,[e[1]||(e[1]=a('<h1 id="requisitos-de-hardware-—-desbravador-enterprise-4-0-—-cloud" tabindex="-1">Requisitos de Hardware — Desbravador Enterprise / 4.0 — Cloud <a class="header-anchor" href="#requisitos-de-hardware-—-desbravador-enterprise-4-0-—-cloud" aria-label="Permalink to &quot;Requisitos de Hardware — Desbravador Enterprise / 4.0 — Cloud&quot;">​</a></h1><p><strong>Sistema:</strong> Desbravador Enterprise / 4.0<br><strong>Modalidade:</strong> Cloud — Totalmente em nuvem<br><strong>Público:</strong> Cliente / Equipe de TI</p><hr><h2 id="historico-de-revisoes" tabindex="-1">Histórico de Revisões <a class="header-anchor" href="#historico-de-revisoes" aria-label="Permalink to &quot;Histórico de Revisões&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Versão</th><th>Data</th><th>Descrição</th><th>Responsável</th></tr></thead><tbody><tr><td>1.0</td><td>Mai/2026</td><td>Criação do documento</td><td>Desbravador Software Ltda.</td></tr><tr><td>1.1</td><td>Mai/2026</td><td>Remoção de referências a produto específico de nuvem; conexão via IP dedicado ou VPN</td><td>Desbravador Software Ltda.</td></tr></tbody></table><hr><blockquote><p>ℹ️ Nesta modalidade, <strong>toda a infraestrutura de aplicação e banco de dados é provisionada e mantida pela Desbravador</strong> na infraestrutura Cloud Desbravador. O cliente não precisa provisionar nenhum servidor. No estabelecimento permanecem apenas as estações de trabalho, os periféricos físicos e o Servidor de Contas para os terminais de PDV.</p></blockquote><blockquote><p>⚠️ <strong>Pré-requisito crítico</strong> — Por não haver servidor de aplicação local, <strong>a operação do sistema depende inteiramente da conectividade com a nuvem</strong>. Um link dedicado ou VPN estável é o principal requisito desta modalidade.</p></blockquote><hr><h2 id="_1-objetivo" tabindex="-1">1. Objetivo <a class="header-anchor" href="#_1-objetivo" aria-label="Permalink to &quot;1. Objetivo&quot;">​</a></h2><p>Este documento orienta o cliente na preparação do ambiente das estações de trabalho e da infraestrutura de rede necessária para a operação do Desbravador Enterprise / 4.0 na modalidade cloud.</p><hr><h2 id="_2-visao-geral-da-arquitetura" tabindex="-1">2. Visão Geral da Arquitetura <a class="header-anchor" href="#_2-visao-geral-da-arquitetura" aria-label="Permalink to &quot;2. Visão Geral da Arquitetura&quot;">​</a></h2>',13)),(t(),n(u,null,{default:o(()=>[c(r,{id:"mermaid-80",class:"mermaid",graph:"flowchart%20TB%0A%20%20%20%20subgraph%20Nuvem%5B%22%E2%98%81%EF%B8%8F%20Cloud%20Desbravador%22%5D%0A%20%20%20%20%20%20%20%20SAPP%5B%22%F0%9F%AA%9F%20Servidor%20de%20Aplica%C3%A7%C3%A3o%5CnDesbravador%20Enterprise%22%5D%0A%20%20%20%20%20%20%20%20BD%5B%22%F0%9F%90%98%20PostgreSQL%2016%5CnBanco%20de%20Dados%22%5D%0A%20%20%20%20%20%20%20%20SAPP%20%3C--%3E%20BD%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20Local%5B%22%F0%9F%8F%A2%20Estabelecimento%22%5D%0A%20%20%20%20%20%20%20%20subgraph%20Rede%5B%22Rede%20Local%20%E2%80%94%20Switch%20Gigabit%22%5D%0A%20%20%20%20%20%20%20%20%20%20%20%20SW%5B%5B%22%E2%87%84%20Switch%22%5D%5D%0A%20%20%20%20%20%20%20%20%20%20%20%20CONTAS%5B%22%F0%9F%AA%9F%20Servidor%20de%20Contas%5Cn(PDV%20%E2%80%94%20local)%22%5D%0A%20%20%20%20%20%20%20%20end%0A%0A%20%20%20%20%20%20%20%20subgraph%20Estacoes%5B%22Esta%C3%A7%C3%B5es%20de%20Trabalho%22%5D%0A%20%20%20%20%20%20%20%20%20%20%20%20FO%5B%22%F0%9F%96%A5%EF%B8%8F%20Front%2FBack-Office%22%5D%0A%20%20%20%20%20%20%20%20%20%20%20%20PDV1%5B%22%F0%9F%96%A5%EF%B8%8F%20PDV%201%22%5D%0A%20%20%20%20%20%20%20%20%20%20%20%20PDVN%5B%22%F0%9F%96%A5%EF%B8%8F%20PDV%20N%22%5D%0A%20%20%20%20%20%20%20%20end%0A%0A%20%20%20%20%20%20%20%20subgraph%20Perifericos%5B%22Perif%C3%A9ricos%22%5D%0A%20%20%20%20%20%20%20%20%20%20%20%20IMP%5B%22%F0%9F%96%A8%EF%B8%8F%20Impressoras%22%5D%0A%20%20%20%20%20%20%20%20%20%20%20%20PIN%5B%22%F0%9F%92%B3%20Pinpads%22%5D%0A%20%20%20%20%20%20%20%20%20%20%20%20FECH%5B%22%F0%9F%94%92%20Fechaduras%22%5D%0A%20%20%20%20%20%20%20%20end%0A%20%20%20%20end%0A%0A%20%20%20%20FO%20--%3E%20SW%0A%20%20%20%20PDV1%20--%3E%20CONTAS%0A%20%20%20%20PDVN%20--%3E%20CONTAS%0A%20%20%20%20CONTAS%20--%3E%20SW%0A%20%20%20%20IMP%20--%3E%20PDV1%0A%20%20%20%20PIN%20--%3E%20PDV1%0A%20%20%20%20FECH%20--%3E%20FO%0A%0A%20%20%20%20SW%20--%20%22IP%20dedicado%5Cnou%20VPN%22%20--%3E%20SAPP%0A"})]),fallback:o(()=>[...e[0]||(e[0]=[l(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=a('<hr><h2 id="_3-responsabilidades" tabindex="-1">3. Responsabilidades <a class="header-anchor" href="#_3-responsabilidades" aria-label="Permalink to &quot;3. Responsabilidades&quot;">​</a></h2><h3 id="_3-1-desbravador-software-ltda" tabindex="-1">3.1 Desbravador Software Ltda. <a class="header-anchor" href="#_3-1-desbravador-software-ltda" aria-label="Permalink to &quot;3.1 Desbravador Software Ltda.&quot;">​</a></h3><ul><li>Provisionamento e manutenção de toda a infraestrutura de servidores na infraestrutura Cloud Desbravador.</li><li>Atualizações de versão aplicadas automaticamente, sem intervenção do cliente.</li><li>Monitoramento de disponibilidade e backup da infraestrutura cloud.</li><li>Suporte técnico durante o período de implantação e operação.</li></ul><h3 id="_3-2-cliente-licenciado" tabindex="-1">3.2 Cliente (LICENCIADO) <a class="header-anchor" href="#_3-2-cliente-licenciado" aria-label="Permalink to &quot;3.2 Cliente (LICENCIADO)&quot;">​</a></h3><ul><li>Prover e manter as estações de trabalho conforme as especificações deste documento.</li><li>Garantir a qualidade e estabilidade do link dedicado ou VPN.</li><li>Instalar e manter periféricos físicos (impressoras, pinpads, fechaduras).</li><li>Manter antivírus instalado e atualizado em todas as estações.</li></ul><blockquote><p>⚠️ <strong>Atenção</strong></p><ul><li>A Desbravador <strong>NÃO</strong> realiza montagem/desmontagem de hardware nas estações do cliente.</li><li>A qualidade da operação está diretamente vinculada à qualidade da conectividade contratada.</li></ul></blockquote><hr><h2 id="_4-servidor-de-contas-—-pdv" tabindex="-1">4. Servidor de Contas — PDV <a class="header-anchor" href="#_4-servidor-de-contas-—-pdv" aria-label="Permalink to &quot;4. Servidor de Contas — PDV&quot;">​</a></h2><p>O módulo de PDV do Desbravador Enterprise / 4.0 utiliza a mesma tecnologia do <strong>Desbravador Fast</strong>. Para operação dos terminais de PDV é necessário um <strong>Servidor de Contas local</strong>, mesmo na modalidade cloud total. Aplicação e banco de dados do sistema principal estão na nuvem, mas os caixas de PDV dependem do Servidor de Contas na rede local.</p><blockquote><p>⚠️ O Servidor de Contas é <strong>sempre local</strong>, mesmo nesta modalidade. Sem ele, os terminais de PDV não operam.</p></blockquote><blockquote><p>ℹ️ Deve ter <strong>IP fixo na rede interna</strong> e estar acessível por todas as estações de caixa.</p></blockquote><table tabindex="0"><thead><tr><th style="text-align:center;">Terminais de PDV</th><th>Processador</th><th style="text-align:center;">RAM</th><th>Armazenamento</th><th>Sistema Operacional</th></tr></thead><tbody><tr><td style="text-align:center;">1 a 15</td><td>Intel Core i5 (12ª geração ou superior) · AMD Ryzen 5 ou superior</td><td style="text-align:center;">8 GB</td><td>SSD NVMe 240 GB</td><td>Windows Server 2022 ou Windows 11 Pro</td></tr><tr><td style="text-align:center;">16 a 40</td><td>Intel Core i7 (12ª geração ou superior) · AMD Ryzen 9 ou superior</td><td style="text-align:center;">16 GB</td><td>SSD NVMe 500 GB</td><td>Windows Server 2022</td></tr><tr><td style="text-align:center;">Acima de 40</td><td>Entre em contato com a equipe de TI da Desbravador para dimensionamento.</td><td style="text-align:center;">—</td><td>—</td><td>—</td></tr></tbody></table><blockquote><p>⚠️ Nobreak (UPS) <strong>obrigatório</strong> no Servidor de Contas.</p></blockquote><hr><h2 id="_5-estacoes-de-trabalho" tabindex="-1">5. Estações de Trabalho <a class="header-anchor" href="#_5-estacoes-de-trabalho" aria-label="Permalink to &quot;5. Estações de Trabalho&quot;">​</a></h2><p>As estações são classificadas por perfil de uso, cada um com requisitos e periféricos distintos. Computadores devem ter no máximo <strong>3 anos de uso</strong> e processadores Intel Core i3/i5/i7/i9 ou AMD Ryzen equivalentes — desconsiderar Celeron, Atom e similares.</p><blockquote><p>ℹ️ <strong>Front-Office e Back-Office</strong> conectam-se ao Cloud Desbravador via IP dedicado ou VPN. <strong>PDV</strong> conecta-se ao Servidor de Contas local (seção 4).</p></blockquote><h3 id="_5-1-front-office-—-recepcao-e-reservas-back-office-—-financeiro-estoque-e-compras" tabindex="-1">5.1 Front-Office — Recepção e Reservas / Back-Office — Financeiro, Estoque e Compras <a class="header-anchor" href="#_5-1-front-office-—-recepcao-e-reservas-back-office-—-financeiro-estoque-e-compras" aria-label="Permalink to &quot;5.1 Front-Office — Recepção e Reservas / Back-Office — Financeiro, Estoque e Compras&quot;">​</a></h3><p>Estações de trabalho utilizadas nos setores operacionais e administrativos do hotel, destinadas às atividades de recepção e atendimento ao hóspede, como realização de check-in, check-out, consultas de reservas e suporte operacional, bem como às rotinas administrativas, incluindo financeiro, gestão de estoque, compras e emissão de relatórios gerenciais. A conexão com o sistema é feita via IP dedicado ou VPN — não há instalação de aplicação local.</p><table tabindex="0"><thead><tr><th>Componente</th><th>Requisito Mínimo</th><th>Recomendado</th></tr></thead><tbody><tr><td><strong>Processador</strong></td><td>Intel Core i3 (12ª geração) · AMD Ryzen 3</td><td>Intel Core i5 ou superior</td></tr><tr><td><strong>Memória RAM</strong></td><td>8 GB</td><td>16 GB</td></tr><tr><td><strong>Armazenamento</strong></td><td>SSD 240 GB</td><td>SSD 500 GB</td></tr><tr><td><strong>Monitor</strong></td><td>Full HD 1920×1080</td><td>Full HD 1920×1080</td></tr><tr><td><strong>Placa de Rede</strong></td><td>Gigabit Ethernet (1000 Mbps)</td><td>Gigabit Ethernet (1000 Mbps)</td></tr><tr><td><strong>Sistema Operacional</strong></td><td>Windows 11 licenciado</td><td>Windows 11 licenciado</td></tr><tr><td><strong>Antivírus</strong></td><td>Obrigatório</td><td>Obrigatório</td></tr><tr><td><strong>Nobreak (UPS)</strong></td><td>Recomendado</td><td>Recomendado</td></tr></tbody></table><h3 id="_5-2-pdv-—-caixa-venda-rapida-e-controle-de-pensao" tabindex="-1">5.2 PDV — Caixa, Venda Rápida e Controle de Pensão <a class="header-anchor" href="#_5-2-pdv-—-caixa-venda-rapida-e-controle-de-pensao" aria-label="Permalink to &quot;5.2 PDV — Caixa, Venda Rápida e Controle de Pensão&quot;">​</a></h3><p>Terminais de ponto de venda. Conectam-se ao <strong>Servidor de Contas local</strong> (seção 4). Windows é <strong>obrigatório</strong> em todas as estações de PDV para integração com periféricos fiscais e de pagamento.</p><table tabindex="0"><thead><tr><th>Componente</th><th>Requisito Mínimo</th><th>Recomendado</th></tr></thead><tbody><tr><td><strong>Processador</strong></td><td>Intel Core i5 (12ª geração) · AMD Ryzen 5</td><td>Intel Core i5/i7 ou superior</td></tr><tr><td><strong>Memória RAM</strong></td><td>8 GB</td><td>16 GB</td></tr><tr><td><strong>Armazenamento</strong></td><td>SSD 240 GB</td><td>SSD 500 GB</td></tr><tr><td><strong>Monitor</strong></td><td>1× Full HD 1920×1080</td><td>Touch screen (venda rápida)</td></tr><tr><td><strong>Portas</strong></td><td>USB + Serial ou adaptador USB-Serial homologado</td><td>—</td></tr><tr><td><strong>Placa de Rede</strong></td><td>Gigabit Ethernet (1000 Mbps)</td><td>Gigabit Ethernet (1000 Mbps)</td></tr><tr><td><strong>Sistema Operacional</strong></td><td><strong>Windows 11 licenciado</strong> (obrigatório)</td><td>Windows 11 Pro</td></tr><tr><td><strong>Antivírus</strong></td><td>Obrigatório</td><td>Obrigatório</td></tr><tr><td><strong>Nobreak (UPS)</strong></td><td><strong>Obrigatório</strong></td><td>Obrigatório</td></tr></tbody></table><blockquote><p>⚠️ O nobreak é <strong>obrigatório</strong> nas estações de PDV — queda de energia durante operação de caixa causa perda de transações e inconsistência fiscal.</p></blockquote><hr><h2 id="_6-requisitos-de-rede-e-conectividade" tabindex="-1">6. Requisitos de Rede e Conectividade <a class="header-anchor" href="#_6-requisitos-de-rede-e-conectividade" aria-label="Permalink to &quot;6. Requisitos de Rede e Conectividade&quot;">​</a></h2><p>Este é o <strong>requisito mais crítico</strong> da modalidade cloud. A qualidade da operação está diretamente ligada à qualidade da conexão com a infraestrutura Cloud Desbravador.</p><h3 id="_6-1-tipo-de-conexao" tabindex="-1">6.1 Tipo de conexão <a class="header-anchor" href="#_6-1-tipo-de-conexao" aria-label="Permalink to &quot;6.1 Tipo de conexão&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Opção</th><th>Descrição</th></tr></thead><tbody><tr><td><strong>IP dedicado</strong></td><td>Link de internet dedicado com IP fixo — conexão direta aos servidores Cloud Desbravador</td></tr><tr><td><strong>VPN</strong></td><td>Túnel VPN sobre link de internet — recomendado quando IP dedicado não está disponível</td></tr></tbody></table><blockquote><p>⚠️ Conexões de internet residencial ou compartilhada não são adequadas para esta modalidade. Oscilações causam falhas de sessão e perda de operação.</p></blockquote><h3 id="_6-2-requisitos-do-link" tabindex="-1">6.2 Requisitos do link <a class="header-anchor" href="#_6-2-requisitos-do-link" aria-label="Permalink to &quot;6.2 Requisitos do link&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Requisito</th><th>Especificação</th></tr></thead><tbody><tr><td><strong>Tipo de link</strong></td><td>Fibra óptica dedicada ou link empresarial</td></tr><tr><td><strong>Latência (RTT)</strong></td><td>≤ 30 ms para os servidores Cloud Desbravador</td></tr><tr><td><strong>Jitter</strong></td><td>≤ 5 ms</td></tr><tr><td><strong>Perda de pacotes</strong></td><td>≤ 0,1%</td></tr></tbody></table><h3 id="_6-3-largura-de-banda-por-quantidade-de-usuarios-simultaneos" tabindex="-1">6.3 Largura de banda por quantidade de usuários simultâneos <a class="header-anchor" href="#_6-3-largura-de-banda-por-quantidade-de-usuarios-simultaneos" aria-label="Permalink to &quot;6.3 Largura de banda por quantidade de usuários simultâneos&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">Usuários simultâneos</th><th style="text-align:center;">Download mínimo</th><th style="text-align:center;">Upload mínimo</th><th>Recomendado</th></tr></thead><tbody><tr><td style="text-align:center;">Até 15</td><td style="text-align:center;">30 Mbps</td><td style="text-align:center;">15 Mbps</td><td>50 Mbps fibra</td></tr><tr><td style="text-align:center;">16 a 40</td><td style="text-align:center;">80 Mbps</td><td style="text-align:center;">40 Mbps</td><td>200 Mbps fibra</td></tr><tr><td style="text-align:center;">Acima de 40</td><td style="text-align:center;">Entre em contato com a equipe de TI da Desbravador para dimensionamento.</td><td style="text-align:center;">—</td><td>—</td></tr></tbody></table><h3 id="_6-4-link-de-contingencia" tabindex="-1">6.4 Link de contingência <a class="header-anchor" href="#_6-4-link-de-contingencia" aria-label="Permalink to &quot;6.4 Link de contingência&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Requisito</th><th>Especificação</th></tr></thead><tbody><tr><td><strong>Obrigatoriedade</strong></td><td><strong>Obrigatório</strong> — sem contingência, falha no link principal paralisa toda a operação</td></tr><tr><td><strong>Tipo</strong></td><td>4G/5G (roteador dedicado) ou segundo link de fibra de provedor diferente</td></tr><tr><td><strong>Ativação</strong></td><td>Automática (failover) ou manual — conforme equipamento de rede</td></tr></tbody></table><h3 id="_6-5-rede-local" tabindex="-1">6.5 Rede local <a class="header-anchor" href="#_6-5-rede-local" aria-label="Permalink to &quot;6.5 Rede local&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Requisito</th><th>Especificação</th></tr></thead><tbody><tr><td><strong>Switch</strong></td><td>Gigabit Ethernet 1000 Mbps</td></tr><tr><td><strong>Cabeamento</strong></td><td>Cat5e mínimo · Cat6 recomendado</td></tr><tr><td><strong>Wi-Fi</strong></td><td>Wi-Fi 5 (802.11ac) mínimo para dispositivos móveis · Wi-Fi 6 recomendado</td></tr></tbody></table><h3 id="_6-6-url-obrigatoria-—-liberacao-em-proxy-firewall-de-saida" tabindex="-1">6.6 URL obrigatória — liberação em proxy/firewall de saída <a class="header-anchor" href="#_6-6-url-obrigatoria-—-liberacao-em-proxy-firewall-de-saida" aria-label="Permalink to &quot;6.6 URL obrigatória — liberação em proxy/firewall de saída&quot;">​</a></h3><blockquote><p>⚠️ O endereço <code>https://servicos.desbravador.com.br/</code> deve estar <strong>permitido (bypass)</strong> em proxies, filtros de conteúdo e firewalls de saída. O bloqueio desta URL impede o funcionamento de serviços essenciais do sistema.</p></blockquote><blockquote><p>ℹ️ Para a configuração de firewall e as portas utilizadas pelo Servidor de Contas e demais serviços Desbravador na rede local, consulte: <a href="./../../infraestrutura/portas-e-firewall.html">Padrão de Portas e Configuração de Firewall</a></p></blockquote><hr><h2 id="_7-dispositivos-moveis-—-ipdv" tabindex="-1">7. Dispositivos Móveis — iPDV <a class="header-anchor" href="#_7-dispositivos-moveis-—-ipdv" aria-label="Permalink to &quot;7. Dispositivos Móveis — iPDV&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requisito</th><th>Especificação</th></tr></thead><tbody><tr><td><strong>Sistema Operacional</strong></td><td>Android 11 ou superior</td></tr><tr><td><strong>Processador</strong></td><td>Quad-core 2 GHz ou superior</td></tr><tr><td><strong>Memória RAM</strong></td><td>4 GB mínimo · 8 GB recomendado</td></tr><tr><td><strong>Armazenamento interno</strong></td><td>32 GB mínimo</td></tr><tr><td><strong>Conectividade</strong></td><td>Wi-Fi 802.11 ac (5 GHz) ou superior</td></tr></tbody></table><blockquote><p>ℹ️ Para a lista completa de dispositivos Smart POS homologados: <a href="./../../perifericos/dispositivos-ipdv-pdv.html">Dispositivos iPDV e PDV homologados</a></p></blockquote><hr><h2 id="_8-perifericos-homologados" tabindex="-1">8. Periféricos Homologados <a class="header-anchor" href="#_8-perifericos-homologados" aria-label="Permalink to &quot;8. Periféricos Homologados&quot;">​</a></h2><p>Periféricos físicos (impressoras, pinpads, fechaduras) são conectados diretamente às estações de trabalho locais.</p><ul><li>🔒 <a href="./../../perifericos/fechaduras-homologadas.html">Fechaduras magnéticas homologadas</a></li><li>🖨️ <a href="./../../perifericos/impressoras-homologadas.html">Impressoras homologadas</a></li><li>💳 <a href="./../../perifericos/pinpads-homologados.html">Pinpads homologados</a></li><li>💳 <a href="./../../perifericos/tef-homologados.html">Sistemas de TEF homologados</a></li><li>📱 <a href="./../../perifericos/dispositivos-ipdv-pdv.html">Dispositivos iPDV e PDV homologados</a></li></ul><hr><h2 id="_9-contato-e-suporte" tabindex="-1">9. Contato e Suporte <a class="header-anchor" href="#_9-contato-e-suporte" aria-label="Permalink to &quot;9. Contato e Suporte&quot;">​</a></h2><p><strong>Desbravador Software Ltda.</strong><br> 🌐 <a href="https://www.desbravador.com.br" target="_blank" rel="noreferrer">www.desbravador.com.br</a></p><p>Para contratação da modalidade cloud ou dúvidas sobre infraestrutura, entre em contato com a equipe técnica da Desbravador.</p>',54))])}const D=d(p,[["render",h]]);export{P as __pageData,D as default};
